const crypto = require('crypto');
const https = require('https');

const appId = $env.GITHUB_APP_ID;
const installationId = $env.GITHUB_INSTALLATION_ID;
const privateKeyBase64 = $env.GITHUB_PRIVATE_KEY_BASE64;
const privateKey = Buffer.from(privateKeyBase64, 'base64').toString('utf8');

const now = Math.floor(Date.now() / 1000);
const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
const payload = Buffer.from(JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId })).toString('base64url');
const signature = crypto.sign('SHA256', Buffer.from(`${header}.${payload}`), privateKey).toString('base64url');
const jwt = `${header}.${payload}.${signature}`;

const token = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.github.com',
    path: `/app/installations/${installationId}/access_tokens`,
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${jwt}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'Content-Length': 0
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => {
      if (res.statusCode !== 201) reject(new Error(`GitHub token request failed: ${res.statusCode} ${body}`));
      else resolve(JSON.parse(body).token);
    });
  });
  req.on('error', reject);
  req.end();
});

return [{ json: { ...$input.first().json, githubToken: token } }];

const trigger = $('Get Installation Token').first().json.body;
const gddRaw = $('Fetch GDD').first().json;
const contextRaw = $('Fetch Project Context').first().json;

const gdd = typeof gddRaw === 'string' ? gddRaw : JSON.stringify(gddRaw);
const projectContext = typeof contextRaw === 'string' ? contextRaw : JSON.stringify(contextRaw);

const systemPrompt = `You are analyzing a new epic for the first time in the Apeiron Cipher game project.

Your goal is NOT to create an SOW yet. Your goal is to understand the ask and surface questions.

Read the epic description. Cross-reference with the GDD and project context.

Identify:
- What's clearly in scope
- What's ambiguous
- What's missing
- What might conflict with existing architecture (ECS plugins, data files, etc.)

Update the epic description to include relevant project-context references (e.g., which ECS plugins are involved, which data files are affected). Return this as a JSON field called "enrichedDescription".

Also write a comment with your questions and observations. Return this as a JSON field called "comment".

Keep your response focused — this will be read on a phone.

Respond with ONLY valid JSON in this format:
{"enrichedDescription": "...", "comment": "..."}

## Game Design Document
${gdd}

## Project Context
${projectContext}`;

const messages = [
  { role: 'system', content: systemPrompt },
  { role: 'user', content: `Epic: ${trigger.issueTitle}\n\n${trigger.issueBody}` }
];

return [{
  json: {
    messages,
    githubToken: $('Get Installation Token').first().json.githubToken,
    repoOwner: trigger.repoOwner,
    repoName: trigger.repoName,
    issueNumber: trigger.issueNumber
  }
}];

const https = require('https');
const llmResponse = $input.first().json;
const prev = $('Build Prompt').first().json;
const token = prev.githubToken;
const owner = prev.repoOwner;
const repo = prev.repoName;
const issueNumber = prev.issueNumber;

const rawContent = llmResponse.choices?.[0]?.message?.content || '';

// Parse the JSON response from the LLM
let enrichedDescription = '';
let comment = '';
try {
  let jsonStr = rawContent.trim();
  // Strip code fences only if they wrap the entire response
  if (jsonStr.startsWith('```json') && jsonStr.endsWith('```')) {
    jsonStr = jsonStr.slice(jsonStr.indexOf('
') + 1, jsonStr.lastIndexOf('```')).trim();
  }
  const parsed = JSON.parse(jsonStr);
  enrichedDescription = parsed.enrichedDescription || '';
  comment = parsed.comment || rawContent;
} catch (e) {
  // If JSON parsing fails, use the entire response as a comment
  comment = rawContent || 'Error: No response from model.';
}

// --- Shared REST helper with retry/rate-limit logic ---
function _rawRequest(method, path, body, tkn) {
  return new Promise((resolve, reject) => {
    const bodyStr = body ? JSON.stringify(body) : '';
    const headers = {
      'Authorization': `Bearer ${tkn}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'X-GitHub-Api-Version': '2022-11-28'
    };
    if (body) {
      headers['Content-Type'] = 'application/json';
      headers['Content-Length'] = Buffer.byteLength(bodyStr);
    }
    const req = https.request({ hostname: 'api.github.com', path, method, headers }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => {
        let parsed;
        try { parsed = JSON.parse(d); } catch(e) { parsed = d; }
        resolve({ status: res.statusCode, data: parsed, headers: res.headers });
      });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

async function githubRest(method, path, body, maxRetries = 3) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const result = await _rawRequest(method, path, body, token);
    if (result.status >= 200 && result.status < 300) return result;
    if (result.status === 403 || result.status === 429) {
      const retryAfter = result.headers['retry-after'];
      const rateLimitReset = result.headers['x-ratelimit-reset'];
      let waitMs;
      if (retryAfter) waitMs = parseInt(retryAfter, 10) * 1000;
      else if (rateLimitReset) waitMs = Math.max((parseInt(rateLimitReset, 10) * 1000) - Date.now(), 1000);
      else waitMs = Math.pow(2, attempt) * 1000;
      if (attempt < maxRetries) { await new Promise(r => setTimeout(r, waitMs)); continue; }
    }
    if (result.status >= 400 && result.status < 500) throw new Error(`GitHub API ${result.status}: ${JSON.stringify(result.data)}`);
    if (result.status >= 500 && attempt < maxRetries) { await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000)); continue; }
    throw new Error(`GitHub API failed after ${maxRetries + 1} attempts: ${result.status}`);
  }
}

// 1. Update epic body with enriched description (if AI provided one)
if (enrichedDescription) {
  await githubRest('PATCH', `/repos/${owner}/${repo}/issues/${issueNumber}`, { body: enrichedDescription });
}

// 2. Post the AI comment
await githubRest('POST', `/repos/${owner}/${repo}/issues/${issueNumber}/comments`, { body: comment });

// 3. Swap needs_refinement → in_scoping
try {
  await githubRest('DELETE', `/repos/${owner}/${repo}/issues/${issueNumber}/labels/${encodeURIComponent('needs_refinement')}`);
} catch (e) { if (!e.message.includes('404')) throw e; }
await githubRest('POST', `/repos/${owner}/${repo}/issues/${issueNumber}/labels`, { labels: ['in_scoping'] });

return [{ json: { success: true, issueNumber, enrichedDescription: !!enrichedDescription, commentPosted: true, labelSwapped: 'needs_refinement -> in_scoping' } }];
